1	'use strict';
2	const jwt = require('jsonwebtoken');
3	const { verifyAzureToken, findOrCreateUser } = require('../services/auth.service');
4	
5	const privateKey = process.env.JWT_PRIVATE_KEY;
6	
7	/**
8	 * POST /auth/azure
9	 * Body: { idToken: <Azure AD ID token> }
10	 * Returns: { status: 'success', token: <Designflow JWT> }
11	 */
12	exports.azureCallback = async (req, res) => {
13	  try {
14	    const { idToken } = req.body;
15	    if (!idToken) {
16	      return res.status(400).json({ status: 'fail', message: 'idToken is required' });
17	    }
18	
19	    const azurePayload = await verifyAzureToken(idToken);
20	    const user         = await findOrCreateUser(azurePayload);
21	
22	    const tokenData = {
23	      name:    `${user.name || ''} ${user.lastname || ''}`.trim(),
24	      user_id: user.id,
25	      email:   user.email,
26	      role:    user.level,
27	    };
28	    if (user.level === 'vendor') {
29	      tokenData.factory_id = user.factory_id;
30	    }
31	
32	    const token = jwt.sign(tokenData, privateKey, {
33	      algorithm: 'RS256',
34	      expiresIn: '12h',
35	    });
36	
37	    return res.json({ status: 'success', token });
38	  } catch (err) {
39	    console.error('[auth/azure]', err.message);
40	    const isTokenError = ['JsonWebTokenError', 'TokenExpiredError', 'NotBeforeError']
41	      .includes(err.name);
42	    const message = isTokenError
43	      ? 'Invalid or expired Azure token'
44	      : 'Authentication failed';
45	    return res.status(401).json({ status: 'fail', message });
46	  }
47	};
