1	const jwt = require("jsonwebtoken");
2	const fs = require("fs");
3	const publicKey = process.env.JWT_PUBLIC_KEY;
4	var verifyOptions = {
5	  algorithm: ["RS256"]
6	};
7	
8	function authToken(req, res, next) {
9	  const token = req.headers.authorization
10	  if (!token) {
11	    return false;
12	  }
13	  try {
14	    const decoded = jwt.verify(token, publicKey, verifyOptions);
15	    req.user = decoded;
16	  } catch (err) {
17	    return false;
18	  }
19	  return true;
20	};
21	
22	
23	function authRole(role) {
24	  return (req, res, next) => {
25	    const token = req.headers.authorization
26	    if (!token) {
27	      return res.status(403).send("A token is required for authentication");
28	    }
29	    return jwt.verify(token, publicKey, verifyOptions, (err, decoded) => {
30	      if (err) {
31	        return res.status(403).send("Invalid Token");
32	      } else {
33	        for (var i = 0; i < role.length; i++) {
34	          if (decoded.role === role[i] || decoded.role === "admin") {
35	            return next();
36	          } 
37	        }
38	        return res.status(401).send("You are not authorized to access this resource");
39	      }
40	    });
41	  }
42	};
43	
44	async function getUserInfo(token) {
45	  return new Promise((resolve) => {
46	    jwt.verify(token, publicKey, verifyOptions, (err, decoded) => {
47	    if (err) {
48	        resolve(null);
49	    } else {
50	        resolve(decoded);
51	    }
52	    });
53	  });
54	};
55	
56	
57	
58	module.exports = { authRole, authToken, getUserInfo }
