1	const jwt = require("jsonwebtoken");
2	
3	function buildLoginTokenPayload(data) {
4	  const payload = {
5	    name: data.name + ' ' + data.lastname,
6	    user_id: data.id,
7	    email: data.email,
8	    role: data.level,
9	  };
10	
11	  if (data.level == 'vendor') {
12	    payload.factory_id = data.factory_id;
13	  }
14	
15	  return payload;
16	}
17	
18	async function createLoginToken(req, data, options = {}) {
19	  const {
20	    comparePassword,
21	    jwtSign = jwt.sign,
22	    privateKey = process.env.JWT_PRIVATE_KEY,
23	  } = options;
24	
25	  if (!req.passw || !data.passw) {
26	    return false;
27	  }
28	
29	  if (typeof comparePassword !== 'function') {
30	    throw new Error('comparePassword is required to create a login token');
31	  }
32	
33	  const passwordMatches = await comparePassword(req.passw, data.passw);
34	  if (!passwordMatches) {
35	    return false;
36	  }
37	
38	  const tokenData = buildLoginTokenPayload(data);
39	  return jwtSign(tokenData, privateKey, {
40	    algorithm: 'RS256',
41	    expiresIn: req.remember ? "30days" : "12h",
42	  });
43	}
44	
45	module.exports = {
46	  buildLoginTokenPayload,
47	  createLoginToken,
48	};
