1	'use strict';
2	const sql = require('../models/db');
3	const GraphPhotoService = require('./graph-photo.service');
4	
5	const UserService = {};
6	
7	/**
8	 * Return { firstName, name, email, photoUrl } for the authenticated user.
9	 * Accepts the decoded JWT ({ user_id, role }). Factory (vendor) users carry a
10	 * vendor_id in user_id and live in the `vendor` table, not `users`, so we must
11	 * branch on role — otherwise a vendor's id is looked up in `users`, misses, and
12	 * the endpoint 404s. Returns null if the user is not found.
13	 */
14	UserService.getProfile = async ({ user_id: userId, role }) => {
15	  if (role === 'vendor') {
16	    const vendor = await sql.vendor.findOne({
17	      where: { vendor_id: userId },
18	      attributes: ['vendor_id', 'vendor_name', 'vendor_lastname', 'vendor_email', 'vendor_profile_photo'],
19	    });
20	    if (!vendor) return null;
21	    return {
22	      firstName: vendor.vendor_name || '',
23	      name: `${vendor.vendor_name || ''} ${vendor.vendor_lastname || ''}`.trim(),
24	      email: vendor.vendor_email || '',
25	      photoUrl: vendor.vendor_profile_photo || null,
26	    };
27	  }
28	  const user = await sql.users.findOne({
29	    where: { id: userId },
30	    attributes: ['id', 'name', 'lastname', 'email', 'profile_photo', 'graph_photo', 'graph_photo_synced_at'],
31	  });
32	  if (!user) return null;
33	  // If the user hasn't uploaded a photo, pull (and cache) their M365/Teams photo
34	  // from Graph. Throttled + best-effort, so /me never fails or stalls on Graph.
35	  let graphPhoto = user.graph_photo;
36	  if (!user.profile_photo) {
37	    graphPhoto = await GraphPhotoService.syncStaffPhoto(user).catch(() => user.graph_photo || null);
38	  }
39	  return {
40	    firstName: user.name || '',
41	    name: `${user.name || ''} ${user.lastname || ''}`.trim(),
42	    email: user.email || '',
43	    photoUrl: user.profile_photo || graphPhoto || null,
44	  };
45	};
46	
47	/**
48	 * Persist a new photo URL for the authenticated user. Returns the URL.
49	 * Branches on role so vendor avatars land in vendor.vendor_profile_photo
50	 * instead of writing to a non-existent users row.
51	 */
52	UserService.updateProfilePhoto = async ({ user_id: userId, role }, photoUrl) => {
53	  if (role === 'vendor') {
54	    await sql.vendor.update(
55	      { vendor_profile_photo: photoUrl },
56	      { where: { vendor_id: userId } }
57	    );
58	  } else {
59	    await sql.users.update(
60	      { profile_photo: photoUrl },
61	      { where: { id: userId } }
62	    );
63	  }
64	  return photoUrl;
65	};
66	
67	module.exports = UserService;
