450	async function uploadSection301(req, res) {
451	  try {
452	    if (!req.file || !req.file.buffer) {
453	      return res.status(400).json({ error: 'No PDF file uploaded. Send as multipart field "pdf".' });
454	    }
455	    if (!req.file.mimetype.includes('pdf') && !req.file.originalname.toLowerCase().endsWith('.pdf')) {
456	      return res.status(400).json({ error: 'Uploaded file must be a PDF.' });
457	    }
458	
459	    // Parse PDF → lookup object
460	    const lookup = await parsePdf(req.file.buffer);
461	    const codesFound = Object.keys(lookup).length;
462	
463	    if (codesFound === 0) {
464	      return res.status(422).json({
465	        error: 'No HTS codes were found in the PDF. Check that this is a USTR Section 301 tariff list.',
466	      });
467	    }
468	
469	    // Store in app_settings, verifying the write round-trips before reporting success.
470	    const storedCount = await persistSection301Lookup(lookup);
471	
472	    // Summarise which lists were found
473	    const lists = [...new Set(Object.values(lookup).map(v => v.list))].sort();
474	
475	    res.json({ codesFound: storedCount, lists });
476	  } catch (err) {
477	    console.error('[section301/upload] error:', err.message);
478	    res.status(500).json({ error: err.message });
479	  }
480	}
