557	/**
558	 * GET /api/admin/section301/lookup?hts=NNNN.NN.NNNN
559	 * Look up a single HTS code in the stored Section 301 data.
560	 *
561	 * Resolution order: admin-curated overrides (app_settings.section301_overrides)
562	 * are checked first — admins use them to fix codes that the PDF parser
563	 * mis-assigned to the wrong list. Falls through to the regex-parsed lookup
564	 * from the uploaded PDF.
565	 *
566	 * Returns: { hts: string, list: string, rate: number, description: string, source: 'override'|'pdf' }
567	 *          or 404 if not found, or 400 if no data has been uploaded yet.
568	 */
569	async function lookupSection301(req, res) {
570	  try {
571	    const { hts } = req.query;
572	    if (!hts) return res.status(400).json({ error: 'hts query param is required' });
573	
574	    // 1. Admin overrides — checked first so they can correct PDF-parse errors
575	    //    without re-uploading. Keys may be 8- or 10-digit; we use the same
576	    //    normalize-and-fall-back lookup logic as the main store.
577	    const overridesRaw = await AppSettingService.get('section301_overrides');
578	    if (overridesRaw) {
579	      let overrides;
580	      try { overrides = JSON.parse(overridesRaw); } catch { overrides = null; }
581	      if (overrides && typeof overrides === 'object') {
582	        const hit = lookupCode(overrides, hts.trim());
583	        if (hit) {
584	          return res.json({ hts, found: true, source: 'override', ...hit });
585	        }
586	      }
587	    }
588	
589	    const raw = await AppSettingService.get('section301_lookup');
590	    if (!raw) {
591	      return res.status(400).json({
592	        error: 'Section 301 data has not been uploaded yet. Go to Editor → AI Settings to upload the PDF.',
593	      });
594	    }
595	
596	    let lookup;
597	    try {
598	      lookup = JSON.parse(raw);
599	    } catch {
600	      return res.status(500).json({ error: 'Stored Section 301 data is corrupted. Please re-upload the PDF.' });
601	    }
602	
603	    const result = lookupCode(lookup, hts.trim());
604	    if (!result) {
605	      return res.status(404).json({ hts, found: false });
606	    }
607	
608	    res.json({ hts, found: true, source: 'pdf', ...result });
609	  } catch (err) {
610	    console.error('[section301/lookup] error:', err.message);
611	    res.status(500).json({ error: err.message });
612	  }
613	}
