633	/**
634	 * GET /api/admin/hts-rates/lookup?hts=NNNN.NN.NNNN
635	 * Look up the MFN general rate for the given HTS code. Falls back from
636	 * 10-digit → 8-digit → 6-digit prefix automatically.
637	 *
638	 * Returns: { hts, found, rate, rateText, description, matchType }
639	 *   - found=false (HTTP 200) when nothing in the schedule matches. A missing
640	 *     code is a normal lookup outcome, not a request error, so the caller can
641	 *     branch on `found` without the global HTTP error interceptor toasting it.
642	 *   - rate may be null even when found=true if the rate is not pure ad valorem
643	 *     (e.g. compound "13.5¢/kg + 4.4%"); the raw rateText is always returned
644	 */
645	async function lookupHtsRate(req, res) {
646	  try {
647	    const { hts } = req.query;
648	    if (!hts) return res.status(400).json({ error: 'hts query param is required' });
649	    const result = htsRates.lookupRate(hts.trim());
650	    if (!result.found) {
651	      return res.json({ hts, found: false, rate: null, rateText: null, description: null, matchType: null });
652	    }
653	    res.json({ ...result });
654	  } catch (err) {
655	    console.error('[hts-rates/lookup] error:', err.message);
656	    res.status(500).json({ error: err.message });
