794	/**
795	 * POST /api/admin/impersonate/:userId
796	 * Admin-only. Issues a short-lived JWT signed as the target user or vendor rep.
797	 * The token carries an extra `impersonated_by` claim (admin's user_id) for audit purposes.
798	 *
799	 * Returns: { token: string }
800	 */
801	async function startImpersonation(req, res) {
802	  try {
803	    const { userId } = req.params;
804	    const { targetType } = req.body || {};
805	    if (!userId) return res.status(400).json({ error: 'userId is required' });
806	
807	    // Prevent impersonating while already impersonating
808	    const callerInfo = await getUserInfo(req.headers.authorization);
809	    if (callerInfo.impersonated_by) {
810	      return res.status(403).json({ error: 'Cannot impersonate while already in an impersonation session' });
811	    }
812	
813	    const privateKey = process.env.JWT_PRIVATE_KEY;
814	    let tokenData;
815	
816	    if (targetType === 'vendor') {
817	      const vendor = await sql.vendor.findOne({
818	        where: { vendor_id: userId },
819	        attributes: [
820	          'vendor_id',
821	          'vendor_name',
822	          'vendor_lastname',
823	          'vendor_email',
824	          'vendor_access',
825	          'vendor_company_nickname',
826	          'factory_id_fk',
827	        ],
828	      });
829	      if (!vendor) return res.status(404).json({ error: 'Vendor not found' });
830	
831	      tokenData = {
832	        name: `${vendor.vendor_name || ''} ${vendor.vendor_lastname || ''}`.trim()
833	          || vendor.vendor_company_nickname
834	          || vendor.vendor_email
835	          || `Vendor ${vendor.vendor_id}`,
836	        user_id: vendor.vendor_id,
837	        email: vendor.vendor_email,
838	        role: 'vendor',
839	        access: vendor.vendor_access,
840	        factory_id: vendor.factory_id_fk,
841	        impersonated_by: callerInfo.user_id,
842	      };
843	    } else if (targetType === 'factory') {
844	      const factory = await sql.Factory.findOne({
845	        where: { id: userId },
846	        attributes: ['id', 'factory_name', 'factory_nickname', 'factory_access'],
847	      });
848	      if (!factory) return res.status(404).json({ error: 'Factory not found' });
849	
850	      const vendor = await sql.vendor.findOne({
851	        where: { factory_id_fk: userId },
852	        attributes: [
853	          'vendor_id',
854	          'vendor_name',
855	          'vendor_lastname',
856	          'vendor_email',
857	          'vendor_access',
858	          'vendor_company_nickname',
859	          'factory_id_fk',
860	        ],
861	        order: [
862	          ['vendor_access', 'ASC'],
863	          ['vendor_id', 'ASC'],
864	        ],
865	      });
866	
867	      tokenData = vendor ? {
868	        name: `${vendor.vendor_name || ''} ${vendor.vendor_lastname || ''}`.trim()
869	          || vendor.vendor_company_nickname
870	          || vendor.vendor_email
871	          || factory.factory_nickname
872	          || factory.factory_name
873	          || `Factory ${factory.id}`,
874	        user_id: vendor.vendor_id,
875	        email: vendor.vendor_email,
876	        role: 'vendor',
877	        access: vendor.vendor_access || factory.factory_access,
878	        factory_id: factory.id,
879	        impersonated_by: callerInfo.user_id,
880	      } : {
881	        name: factory.factory_nickname || factory.factory_name || `Factory ${factory.id}`,
882	        user_id: factory.id,
883	        email: null,
884	        role: 'vendor',
885	        access: factory.factory_access,
886	        factory_id: factory.id,
887	        impersonated_by: callerInfo.user_id,
888	      };
889	    } else {
890	      const targetUser = await sql.users.findOne({
891	        where: { id: userId },
892	        attributes: ['id', 'name', 'lastname', 'email', 'level'],
893	      });
894	      if (!targetUser) return res.status(404).json({ error: 'User not found' });
895	
896	      tokenData = {
897	        name: `${targetUser.name || ''} ${targetUser.lastname || ''}`.trim(),
898	        user_id: targetUser.id,
899	        email: targetUser.email,
900	        role: targetUser.level,
901	        impersonated_by: callerInfo.user_id,
902	      };
903	
904	      if (targetUser.level === 'vendor') {
905	        const vendor = await sql.vendor.findOne({
906	          where: { vendor_email: targetUser.email },
907	          attributes: ['vendor_access', 'factory_id_fk'],
908	        });
909	        if (vendor) {
910	          tokenData.access = vendor.vendor_access;
911	          tokenData.factory_id = vendor.factory_id_fk;
912	        }
913	      }
914	    }
915	
916	    const token = jwt.sign(tokenData, privateKey, {
917	      algorithm: 'RS256',
918	      expiresIn: '2h',
919	    });
920	
921	    res.json({ token });
922	  } catch (err) {
923	    console.error('[admin/impersonate] error:', err.message);
924	    res.status(500).json({ error: 'Impersonation failed' });
925	  }
926	}
